/**
 * @summary List pattern observations and suggestions
 */
export const getListPatternsUrl = (params?: ListPatternsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/patterns?${stringifiedParams}`
    : `/api/patterns`;
};

export const listPatterns = async (
  params?: ListPatternsParams,
  options?: RequestInit,
): Promise<PatternObservation[]> => {
  return customFetch<PatternObservation[]>(getListPatternsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListPatternsQueryKey = (params?: ListPatternsParams) => {
  return [`/api/patterns`, ...(params ? [params] : [])] as const;
};

export const getListPatternsQueryOptions = <
  TData = Awaited<ReturnType<typeof listPatterns>>,
  TError = ErrorType<unknown>,
>(
  params?: ListPatternsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listPatterns>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListPatternsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listPatterns>>> = ({
    signal,
  }) => listPatterns(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listPatterns>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

